enum WebViewRestorationType {
    case userActivity(NSUserActivity)
    case coder(NSCoder)
    case server(Server)

    init?(_ userActivity: NSUserActivity?) {
        if let userActivity {
            self = .userActivity(userActivity)
        } else {
            return nil
        }
    }

    var initialURL: URL? {
        switch self {
        case let .userActivity(userActivity):
            return userActivity.userInfo?[RestorableStateKey.lastURL.rawValue] as? URL
        case let .coder(coder):
            return coder.decodeObject(of: NSURL.self, forKey: RestorableStateKey.lastURL.rawValue) as URL?
        case .server:
            return nil
        }
    }

    var server: Server? {
        let serverRawValue: String?

        switch self {
        case let .userActivity(userActivity):
            serverRawValue = userActivity.userInfo?[RestorableStateKey.server.rawValue] as? String
        case let .coder(coder):
            serverRawValue = coder.decodeObject(
                of: NSString.self,
                forKey: RestorableStateKey.server.rawValue
            ) as String?
        case let .server(server):
            return server
        }

        return Current.servers.server(forServerIdentifier: serverRawValue)
    }
}

import Foundation

public enum OnboardingState: Equatable {
    public enum NeededType: Equatable {
        case logout
        case error
        case unauthenticated(_ serverId: String, _ code: Int)

        public var shouldShowError: Bool {
            switch self {
            case .logout: return false
            case .error: return true
            case .unauthenticated: return false
            }
        }
    }

    case complete
    case didConnect
    case needed(NeededType)
}

public protocol OnboardingStateObserver: AnyObject {
    func onboardingStateDidChange(to state: OnboardingState)
}

public class OnboardingStateObservation {
    private var observers = NSHashTable<AnyObject>(options: .weakMemory)

    public func register(observer: OnboardingStateObserver) {
        observers.add(observer)
    }

    public func unregister(observer: OnboardingStateObserver) {
        observers.remove(observer)
    }

    private func notify(for state: OnboardingState) {
        observers
            .allObjects
            .compactMap { $0 as? OnboardingStateObserver }
            .forEach { $0.onboardingStateDidChange(to: state) }
    }

    public func complete() {
        notify(for: .complete)
    }

    public func needed(_ type: OnboardingState.NeededType) {
        notify(for: .needed(type))
    }

    public func didConnect() {
        notify(for: .didConnect)
    }
}

package final class RulesFilter {
    package struct ExcludingOptions: OptionSet {
        package let rawValue: Int

        package init(rawValue: Int) {
            self.rawValue = rawValue
        }

        package static let enabled = Self(rawValue: 1 << 0)
        package static let disabled = Self(rawValue: 1 << 1)
        package static let uncorrectable = Self(rawValue: 1 << 2)
    }

    private let allRules: RuleList
    private let enabledRules: [any Rule]

    package init(allRules: RuleList = RuleRegistry.shared.list, enabledRules: [any Rule]) {
        self.allRules = allRules
        self.enabledRules = enabledRules
    }

    package func getRules(excluding excludingOptions: ExcludingOptions) -> RuleList {
        if excludingOptions.isEmpty {
            return allRules
        }

        let filtered: [any Rule.Type] = allRules.list.compactMap { ruleID, ruleType in
            let enabledRule = enabledRules.first { rule in
                type(of: rule).identifier == ruleID
            }
            let isRuleEnabled = enabledRule != nil

            if excludingOptions.contains(.enabled), isRuleEnabled {
                return nil
            }
            if excludingOptions.contains(.disabled), !isRuleEnabled {
                return nil
            }
            if excludingOptions.contains(.uncorrectable), !(ruleType is any CorrectableRule.Type) {
                return nil
            }

            return ruleType
        }

        return RuleList(rules: filtered)
    }
}

